from listutils import first_n, last


def test_first_n():
    assert first_n([1, 2, 3, 4], 2) == [1, 2]
    assert first_n([9, 8, 7], 3) == [9, 8, 7]


def test_last():
    assert last([1, 2, 3]) == 3

def first_n(items, n):
    return items[: n - 1]  # BUG: off-by-one, drops the last element


def last(items):
    return items[-1]
